import{_ as a,o,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"OBD2 Simulator","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/obdii-simulators/libraries/obd2-simulator.md","filePath":"obd2/obdii-simulators/libraries/obd2-simulator.md"}'),i={name:"obd2/obdii-simulators/libraries/obd2-simulator.md"};function s(n,e,l,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="obd2-simulator" tabindex="-1">OBD2 Simulator <a class="header-anchor" href="#obd2-simulator" aria-label="Permalink to &quot;OBD2 Simulator&quot;">​</a></h1><h2 id="story" tabindex="-1">Story <a class="header-anchor" href="#story" aria-label="Permalink to &quot;Story&quot;">​</a></h2><p>It was troublesome to have to prepare a vehicle when making OBD2 device and related services. With this OBD2 simulator, you can develop OBD2 equipment on the desk without going to the garage.</p><p>12V DC power required. When BLE is connected to the mobile device, various parameters, engine speed, car speed, coolant temperature, etc. can be set with the slider bar.</p><p>You can modify the software by Arduino IDE by connecting the PC through the micro USB connection.</p><p>The idea of the design is based on <a href="https://www.hackster.io/ebaera/obd2-robot-controller-car-mate" target="_blank" rel="noreferrer">OBD2 Robot Controller &quot;CAR MATE</a>.&quot; Protocol IC is MCP2515 and I used the Arduino-compatible library: <a href="https://github.com/coryjfowler/MCP_CAN_lib" target="_blank" rel="noreferrer">https://github.com/coryjfowler/MCP_CAN_lib</a>. I found <a href="https://www.amazon.com/gp/product/B0141UPYDC/ref=oh_aui_detailpage_o02_s00?ie=UTF8&amp;psc=1" target="_blank" rel="noreferrer">OBD2 Connector</a> in amazon.com.</p><p>Read more</p><h3 id="custom-parts-and-enclosures" tabindex="-1">Custom parts and enclosures <a class="header-anchor" href="#custom-parts-and-enclosures" aria-label="Permalink to &quot;Custom parts and enclosures&quot;">​</a></h3><h3 id="schematics" tabindex="-1">Schematics <a class="header-anchor" href="#schematics" aria-label="Permalink to &quot;Schematics&quot;">​</a></h3><h3 id="code" tabindex="-1">Code <a class="header-anchor" href="#code" aria-label="Permalink to &quot;Code&quot;">​</a></h3><h3 id="credits" tabindex="-1">Credits <a class="header-anchor" href="#credits" aria-label="Permalink to &quot;Credits&quot;">​</a></h3>',11)])])}const b=a(i,[["render",s]]);export{m as __pageData,b as default};
